from pytest_pyodide import run_in_pyodide


@run_in_pyodide(packages=["sentencepiece"])
def test_simple_sentencepiece(selenium):
    import base64
    from tempfile import NamedTemporaryFile
    import sentencepiece

    # Base64 blob sourced from:
    # https://github.com/google/sentencepiece/blob/439fec3ade0a9f8a1e6bc3903597582587ec0f9b/python/test/test_model.model
    test_model = ""  # noqa
    model_file = NamedTemporaryFile().name
    with open(model_file, 'wb') as w:
        w.write(base64.b64decode(test_model))  # write the model to a temporary file

    # Test reading in a model from a file and encoding a string from the README example.
    processor = sentencepiece.SentencePieceProcessor(model_file=model_file)
    assert processor.encode('This is a test') == [284, 47, 11, 4, 15, 400]
